二叉排序树

二叉排序树（Binary Sort Tree），又称二叉查找树（Binary Search Tree），亦称二叉搜索树。
二叉排序树是一种比较有用的折衷方案。数组的搜索比较方便，可以直接用下标。链表与之相反，删除和插入元素很快，但查找很慢。二叉排序树就既有链表的好处，也有数组的好处。在处理大批量的动态的数据是比较有用。
二叉排序树或者是一棵空树，或者是具有下列性质的二叉树：

若左子树不空，则左子树上所有结点的值均小于或等于它的根结点的值；

若右子树不空，则右子树上所有结点的值均大于或等于它的根结点的值；

左、右子树也分别为二叉排序树；



创建二叉树

function BinaryTree(){
    var Node=function(key){
        this.key=key
        this.left=null
        this.right=null
    }
    var root = null
    var insertNode=function(node,newNode){
        if(newNode.key 
先序遍历 复制二叉树

先序遍历：（1）访问根节点；（2）采用先序递归遍历左子树；（3）采用先序递归遍历右子树
this.preOrderTraverse=function(callback){
    preOrderTraverseNode(root,callback)
}
var preOrderTraverseNode=function(node,callback){
    if(node!==null){
        callback(node.key)
        preOrderTraverseNode(node.left,callback)
        preOrderTraverseNode(node.right,callback)
    }
}

后序遍历

后序遍历：（1）采用后序递归遍历左子树；（2）采用后序递归遍历右子树；（3）访问根节点
this.postOrderTraverse=function(callback){
    postOrderTraverseNode(root,callback)
}
var postOrderTraverseNode=function(node,callback){
    if(node!==null){
        postOrderTraverseNode(node.left,callback)
        postOrderTraverseNode(node.right,callback)
        callback(node.key)
    }
}

中序遍历 升序排列

中序遍历：（1）采用中序遍历左子树；（2）访问根节点；（3）采用中序遍历右子树
this.inOrderTraverse=function(callback){
    inOrderTraverseNode(root,callback)
}
var inOrderTraverseNode=function(node,callback){
    if(node!==null){    
        inOrderTraverseNode(node.left,callback)
        callback(node.key)
        inOrderTraverseNode(node.right,callback)
    }
}

查找最小值

this.min=function(){
    return minNode(root)
}
var minNode=function(node){
    if(node){
        while(node && node.left!==null){
            node=node.left
        }
        return node.key
    }
}

查找最大值

this.max=function(){
    return maxNode(root)
}
var maxNode=function(node){
    if(node){
        while(node && node.right!==null){
            node=node.right
        }
        return node.key
    }
}

查找是否存在对应值

this.search=function(key){
    return searchNode(root,key)
}
var searchNode=function(node,key){
    if(node === null) return false
    if(key  node.key){
        return searchNode(node.right,key)
    }else{
        return true
    }
}

删除节点

this.remove=function(key){
    root=removeNode(root,key)
}
var findMinNode=function(node){
    if(node){
        while(node && node.left!==null){
            node=node.left
        }
        return node
    }
}
var removeNode=function(node,key){
    if(node===null) return null
    if(key  node.right){
        node.right=removeNode(node.right,key)
        return node
    }else{
        // 叶子节点
        if(node.left === null && node.right === null){
            node = null
            return node
        }
        // 只包含右子树
        if(node.left === null){
            node=node.right
            return node
        }
        // 只包含左子树
        if(node.right === null){
            node=node.left
            return node
        }
        // 包含左右子树(查找右子树的最小节点删除并修改当前节点的key值)
        var aux=findMinNode(node.right)
        node.key=aux.key
        node.right=removeNode(node.right,aux.key)
        return node
    }
}

DEMO

代码测试地址：https://github.com/Leooman/Leooman.github.io/issues/1

性能分析

每个结点的C(i)查找次数为该结点的层次数。
最坏情况下，当先后插入的关键字有序时，构成的二叉排序树蜕变为单支树，树的深度为其平均查找长度(n+1)/2(和顺序查找相同）

最好的情况是二叉排序树的形态和折半查找的判定树相同，其平均查找长度和log 2 (n)成正比。
为了提高二叉排序树的查找效率，需要把树构建得更为平衡，从而不出现左右偏重的情况，这就引出了AVL树(通过树高差限定)和红黑树(通过颜色标识限定)等平衡二叉树。 
